import{_ as s,o as a,c as n,b as e}from"./chunks/plugin-vue_export-helper.B0FdOn3A.js";const _=JSON.parse('{"title":"Чувство сопротивления","description":"","frontmatter":{"title":"Чувство сопротивления","date":"2020-09-13T00:00:00.000Z"},"headers":[],"relativePath":"posts/2020-09-13-resistance.md","filePath":"posts/2020-09-13-resistance.md"}'),l={name:"posts/2020-09-13-resistance.md"};function r(o,t,p,c,i,d){return a(),n("div",null,[...t[0]||(t[0]=[e("p",null,"В самом чувстве сопротивления нет ничего хорошего или плохого (привет оценочному суждению). Это механизм защиты от неблагоприятных внешних факторов. Всё ради того чтобы сохранить привычный образ жизни и deal with вторжениями и террором.",-1),e("p",null,'Если человек может сказать "Нет, я против!" это воспринимается нормальным, человек хорошо понимает свои границы и отстаивает свои интересы. Но бывают ситуации, когда неблагоприятные факторы отсутствуют, а сопротивление чувствуется.',-1),e("p",null,"Сопротивление возникает при попытках выбраться из состояния стагнации, гомеостаза, привычного образа жизни. Даже если этот образ жизни деструктивен и наполнен негативными переживаниями. Так уж устроена психика.",-1),e("p",null,'Многим известен принцип психологического айкидо - сначала согласитесь с оппонентом, а потом выскажите свою точку зрения. Но здесь есть пара нюансов - если вы согласны только на словах, оппонент все равно чувствует ваше сопротивление в голосе, интонациях. Второй момент - за психологическим айкидо часто скрывается неумение говорить "нет" когда это действительно нужно.',-1),e("p",null,"В восточных боевых искусствах устойчивость достигается через мягкость. При столкновении тело сначала резко наполняется силой, а потом моментально становится как бы прозрачным. Мягкость обескураживает ожидающего сопротивление противника, как и внезапная техничная резкость. Расслабленную руку гораздо проще убрать из захвата.",-1),e("p",null,"Существуют разные подходы к преодолению сопротивления. Я писал эту статью почти три дня. Очень много чувства сопротивления у меня возникло, болела голова, появлялись более важные дела. Это новая для меня тема, я в ней вообще не разбираюсь, что обо мне скажут знающие люди? Страх оценки, я могу выглядеть глупо. Или страх перед тем, что в результате самоанализа я откопаю что-то страшное. Возникает реальное сопротивление перед воображаемой ситуацией в будущем.",-1),e("p",null,"Все входят в холодную реку по-разному, я - постепенно, а кто-то представляет себя берсерком и идёт напролом. А кто-то вообще не заходит, предпочитая игру в поддавки. А у кого-то холодная река вообще не вызывает сопротивления.",-1)])])}const m=s(l,[["render",r]]);export{_ as __pageData,m as default};
